import React from "react";
import { Table, Tag, Typography, Progress, theme } from "antd";
import { StorageInfo } from "../data/mockData";
import { useI18n } from "@/framework/i18n/hooks";

const { Text } = Typography;

interface StatusGridProps {
  items: StorageInfo[];
  selectedId?: string;
  onSelect: (item: StorageInfo) => void;
}

export default function StatusGrid({ items, selectedId, onSelect }: StatusGridProps) {
  const { t } = useI18n(["storageLocker"]);

  const columns = [
    {
      title: t("storageLocker:dashboard.lockerName"),
      dataIndex: "name",
      key: "name",
      render: (text: string) => <Text strong>{text}</Text>,
    },
    {
      title: t("storageLocker:dashboard.status"),
      dataIndex: "connectState",
      key: "connectState",
      align: "center" as const,
      render: (state: "on" | "off") => (
        <Tag color={state === "on" ? "success" : "error"}>
          {state === "on" ? t("storageLocker:dashboard.on") : t("storageLocker:dashboard.off")}
        </Tag>
      ),
    },
    {
      title: t("storageLocker:dashboard.temp"),
      dataIndex: "temperature",
      key: "temperature",
      render: (val: number) => (
        <div style={{ width: 120 }}>
          <Progress 
            percent={Math.min(100, (val / 50) * 100)} 
            size="small" 
            format={() => `${val}°C`}
            strokeColor={val > 30 ? "#ff4d4f" : "#1890ff"}
          />
        </div>
      ),
    },
    {
      title: t("storageLocker:dashboard.humi"),
      dataIndex: "humidity",
      key: "humidity",
      render: (val: number) => (
        <div style={{ width: 120 }}>
          <Progress 
            percent={val} 
            size="small" 
            format={() => `${val}%`}
            strokeColor="#52c41a"
          />
        </div>
      ),
    },
    {
      title: t("storageLocker:dashboard.lastSync"),
      dataIndex: "lastDt",
      key: "lastDt",
      render: (text: string) => <Text type="secondary" style={{ fontSize: 12 }}>{text}</Text>,
    },
  ];

  return (
    <Table 
      dataSource={items} 
      columns={columns} 
      rowKey="id"
      size="small"
      pagination={false}
      onRow={(record) => ({
        onClick: () => onSelect(record),
        className: record.id === selectedId ? "selected-row" : "",
        style: { 
          cursor: "pointer",
          transition: "all 0.3s"
        }
      })}
      components={{
        body: {
          row: (rowProps: any) => {
            const isSelected = rowProps["data-row-key"] === selectedId;
            const { token: rowToken } = theme.useToken();
            const rowRef = React.useRef<HTMLTableRowElement>(null);
            
            React.useEffect(() => {
              if (isSelected && rowRef.current) {
                rowRef.current.scrollIntoView({ behavior: "smooth", block: "nearest" });
              }
            }, [isSelected]);

            return (
              <tr 
                {...rowProps} 
                ref={rowRef}
                style={{ 
                  ...rowProps.style,
                  backgroundColor: isSelected ? rowToken.colorPrimaryBg : "inherit",
                  borderLeft: isSelected ? `4px solid ${rowToken.colorPrimary}` : "none",
                  transition: "all 0.3s"
                }} 
              />
            );
          }
        }
      }}
    />
  );
}
