import React, { useEffect } from "react";
import { MapContainer, TileLayer, Marker, Popup, useMap } from "react-leaflet";
import L from "leaflet";
import { theme } from "antd";
import { StorageInfo } from "../data/mockData";
import { useI18n } from "@/framework/i18n/hooks";

// Fix for default marker icons
import markerIcon2x from "leaflet/dist/images/marker-icon-2x.png";
import markerIcon from "leaflet/dist/images/marker-icon.png";
import shadowIcon from "leaflet/dist/images/marker-shadow.png";

// @ts-ignore
delete L.Icon.Default.prototype._getIconUrl;
L.Icon.Default.mergeOptions({
  iconRetinaUrl: markerIcon2x,
  iconUrl: markerIcon,
  shadowUrl: shadowIcon,
});

const { useToken } = theme;

function MapResizer() {
  const map = useMap();
  useEffect(() => {
    const container = map.getContainer();
    const resizeObserver = new ResizeObserver(() => { map.invalidateSize(); });
    resizeObserver.observe(container);
    map.invalidateSize();
    return () => resizeObserver.disconnect();
  }, [map]);
  return null;
}

function MapController({ selectedItem, items }: { selectedItem: StorageInfo | null, items: StorageInfo[] }) {
  const map = useMap();
  useEffect(() => {
    if (selectedItem) {
      map.setView([selectedItem.lat, selectedItem.lng], 16, { animate: true });
    } else if (items.length > 0) {
      const bounds = L.latLngBounds(items.map((it) => [it.lat, it.lng]));
      map.fitBounds(bounds, { padding: [50, 50], animate: true });
    }
  }, [map, selectedItem, items]);
  return null;
}

interface MapViewProps {
  items: StorageInfo[];
  selectedId?: string;
  onSelect: (item: StorageInfo) => void;
}

export default function MapView({ items, selectedId, onSelect }: MapViewProps) {
  const { token } = useToken();
  const { t } = useI18n(["storageLocker", "platform", "common"]);

  const getCustomIcon = (item: StorageInfo) => {
    const isSelected = item.id === selectedId;
    const color = item.connectState === "on" ? "#52c41a" : "#ff4d4f";
    const statusText = item.connectState === "on" ? t("storageLocker:dashboard.on") : t("storageLocker:dashboard.off");
    const scale = isSelected ? 1.3 : 1.0;
    const shadow = isSelected ? `0 0 20px ${color}` : `0 0 10px ${color}`;

    return L.divIcon({
      className: "custom-storage-marker",
      html: `
        <div style="position: relative; width: 120px; transition: transform 0.3s ease; transform: translate(-50%, -100%) scale(${scale});">
          <div style="
            background: rgba(0, 0, 0, ${isSelected ? 0.9 : 0.7});
            color: white;
            padding: 4px 8px;
            border-radius: 4px;
            font-size: ${isSelected ? "13px" : "11px"};
            font-weight: ${isSelected ? "bold" : "normal"};
            text-align: center;
            border: 1px solid ${isSelected ? "#fff" : "rgba(255,255,255,0.2)"};
            white-space: nowrap;
            box-shadow: 0 4px 8px rgba(0,0,0,0.5);
          ">
            ${item.name}
          </div>
          <div style="
            background: ${color};
            width: ${isSelected ? "12px" : "8px"};
            height: ${isSelected ? "12px" : "8px"};
            border-radius: 50%;
            border: 2px solid white;
            margin: 4px auto 0;
            box-shadow: ${shadow};
            ${item.connectState === "off" ? "animation: blink 0.8s infinite;" : ""}
          "></div>
        </div>
        <style>
          @keyframes blink { 0% { opacity: 0; } 100% { opacity: 1; } }
        </style>
      `,
      iconSize: [0, 0],
      iconAnchor: [0, 0],
    });
  };

  const selectedItem = items.find(it => it.id === selectedId) || null;

  return (
    <div style={{ width: "100%", height: "100%", position: "relative", overflow: "hidden" }}>
      <style>{`
        .leaflet-tile-pane { filter: ${token.colorBgLayout.includes('#') && (parseInt(token.colorBgLayout.replace('#',''), 16) < 0x222222) ? "invert(100%) hue-rotate(180deg) brightness(95%) contrast(90%)" : "none"}; }
      `}</style>
      <MapContainer center={[35.5, 129.2]} zoom={11} style={{ width: "100%", height: "100%" }} zoomControl={false}>
        <TileLayer 
          attribution='&copy; OpenStreetMap' 
          url="https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png" 
        />
        <MapResizer />
        <MapController selectedItem={selectedItem} items={items} />
        {items.map((it) => (
          <Marker 
            key={it.id} 
            position={[it.lat, it.lng]} 
            icon={getCustomIcon(it)}
            eventHandlers={{ click: () => onSelect(it) }}
          >
            <Popup>
              <div style={{ padding: "4px 0" }}>
                <div style={{ fontWeight: "bold", fontSize: 16 }}>{it.name}</div>
                <div style={{ color: "#666", marginBottom: 8 }}>{it.address}</div>
                <div style={{ display: "flex", gap: 12, fontSize: 13 }}>
                  <span>{t("storageLocker:dashboard.temp")}: <b>{it.temperature}°C</b></span>
                  <span>{t("storageLocker:dashboard.humi")}: <b>{it.humidity}%</b></span>
                </div>
              </div>
            </Popup>
          </Marker>
        ))}
      </MapContainer>
    </div>
  );
}
